import React from 'react';
import {Routes, Route, Navigate, useParams} from 'react-router-dom';
import { connect } from 'react-redux';

import './App.css';

import HomePage from './pages/homepage/homepage.component';
import ShopPage from './pages/shop/shop.component';
import CheckoutPage from './pages/checkout/checkout.component';
import SignInAndSignUp from './pages/sign-in-and-sign-up/sign-in-and-sign-up.component';
import CollectionPage from './pages/collection/collection.component';
import Header from './components/header/header.component';
import Directory from './components/directory-menu/directory-menu.component'
import NoMatch from './components/no-match/no-match.component';



import { addCollectionAndDocument, auth, createUserProfileDocument} from './firebase/firebase.utils';
import { onSnapshot } from 'firebase/firestore';
import { setCurrentUser } from './redux/user/user.actions';
import { createStructuredSelector } from 'reselect';
import { selectCurrentUser } from './redux/user/user.selector';
import { selectCollectionsForPreview } from './redux/shop/shop.selector';


class App extends React.Component {

  unsubscribeFromAuth = null;

//  check if user is stored on our database
  componentDidMount() {

    const { setCurrentUser } = this.props 
    this.unsubscribeFromAuth = auth.onAuthStateChanged(async userAuth => {

      if (userAuth) {
        const userRef = await createUserProfileDocument(userAuth);

        onSnapshot(userRef, (doc) => {
            setCurrentUser({
              id: doc.id,
              ...doc.data()
          });
        });
      } 

      setCurrentUser(userAuth);
      addCollectionAndDocument('collection', collectionsArray.map(({title, items})=> ({title, items})) 
    );
    });

  }

  componentWillUnmount() {
    this.unsubscribeFromAuth();
  }

  render () {

    return (
      <div>
        <Header />
        <Routes>
          <Route  path="/" element={<HomePage />} />
          <Route  path="/shop" element={<ShopPage />} />
          <Route  path="/shop/:collectionId" element={<CollectionPage />} />
          <Route exact path="/checkout" element={<CheckoutPage />} />
            <Route exact 
            path='/signin' 
            element={
              this.props.currentUser ? (
                <Navigate replace to="/" />
              ):(
                <SignInAndSignUp />
              )  
            } 
            />
            <Route path="*" element={<NoMatch />} />
        </Routes>
      </div>
  );
  }

};

const mapStatetoProps = createStructuredSelector({
  currentUser: selectCurrentUser,
  collectionsArray: selectCollectionsForPreview
});

const mapDispatchToProps = (dispatch) => ({
    setCurrentUser: (user) => dispatch(setCurrentUser(user))
  }
)

export default connect(mapStatetoProps, mapDispatchToProps)(App);
